from flask import Flask, request, jsonify
import psycopg2
import psycopg2.extras
import os
import re

app = Flask(__name__)

DB_CONFIG = {
    "host": os.getenv("PGHOST", "localhost"),
    "port": os.getenv("PGPORT", "5432"),
    "dbname": os.getenv("PGDATABASE", "postgres"),
    "user": os.getenv("PGUSER", "postgres"),
    "password": os.getenv("PGPASSWORD", "postgres"),
}

IDENTIFIER_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

ALLOWED_OPERATORS = {
    "=": "=",
    "!=": "!=",
    "<>": "<>",
    "<": "<",
    "<=": "<=",
    ">": ">",
    ">=": ">=",
    "like": "LIKE",
    "ilike": "ILIKE",
    "in": "IN",
    "not in": "NOT IN",
    "is": "IS",
    "is not": "IS NOT",
}


def get_conn():
    return psycopg2.connect(**DB_CONFIG)


def validate_identifier(name):
    if not isinstance(name, str) or not IDENTIFIER_RE.match(name):
        raise ValueError(f"Invalid identifier: {name}")
    return name


def validate_column_list(columns):
    if columns is None:
        return ["*"]
    if not isinstance(columns, list) or not columns:
        raise ValueError("columns must be a non-empty list or omitted")
    validated = []
    for col in columns:
        validated.append(validate_identifier(col))
    return validated


def build_where_clause(filters, params):
    if not filters:
        return "", params

    if not isinstance(filters, list):
        raise ValueError("filters must be a list")

    clauses = []
    for f in filters:
        if not isinstance(f, dict):
            raise ValueError("each filter must be an object")

        column = validate_identifier(f.get("column"))
        operator_raw = f.get("operator")
        if not isinstance(operator_raw, str):
            raise ValueError("operator must be a string")
        operator_key = operator_raw.strip().lower()
        if operator_key not in ALLOWED_OPERATORS:
            raise ValueError(f"Unsupported operator: {operator_raw}")

        operator = ALLOWED_OPERATORS[operator_key]
        value = f.get("value")

        if operator_key in {"in", "not in"}:
            if not isinstance(value, list) or len(value) == 0:
                raise ValueError(f"{operator_raw} requires a non-empty list value")
            placeholders = []
            for item in value:
                params.append(item)
                placeholders.append(f"%s")
            clauses.append(f"{psycopg2.extensions.AsIs(column).string} {operator} ({', '.join(placeholders)})")
        elif operator_key in {"is", "is not"}:
            if value is not None and not (isinstance(value, str) and value.lower() in {"null", "true", "false"}):
                raise ValueError("IS / IS NOT supports null, true, or false")
            if value is None or (isinstance(value, str) and value.lower() == "null"):
                clauses.append(f"{psycopg2.extensions.AsIs(column).string} {operator} NULL")
            else:
                params.append(value if not isinstance(value, str) else value.lower() == "true")
                clauses.append(f"{psycopg2.extensions.AsIs(column).string} {operator} %s")
        else:
            params.append(value)
            clauses.append(f"{psycopg2.extensions.AsIs(column).string} {operator} %s")

    return " WHERE " + " AND ".join(clauses), params


@app.route("/query", methods=["POST"])
def query():
    try:
        payload = request.get_json(force=True, silent=False)
        if not isinstance(payload, dict):
            return jsonify({"error": "JSON body must be an object"}), 400

        table = validate_identifier(payload.get("table"))
        columns = validate_column_list(payload.get("columns"))
        filters = payload.get("filters")
        limit = payload.get("limit", 100)
        offset = payload.get("offset", 0)
        order_by = payload.get("order_by")

        if not isinstance(limit, int) or limit < 1 or limit > 10000:
            return jsonify({"error": "limit must be an integer between 1 and 10000"}), 400
        if not isinstance(offset, int) or offset < 0:
            return jsonify({"error": "offset must be a non-negative integer"}), 400

        params = []
        select_part = "*"
        if columns != ["*"]:
            select_part = ", ".join(columns)

        query_sql = f"SELECT {select_part} FROM {table}"

        where_clause, params = build_where_clause(filters, params)
        query_sql += where_clause

        if order_by is not None:
            if not isinstance(order_by, dict):
                return jsonify({"error": "order_by must be an object with column and direction"}), 400
            order_col = validate_identifier(order_by.get("column"))
            direction = str(order_by.get("direction", "asc")).lower()
            if direction not in {"asc", "desc"}:
                return jsonify({"error": "order_by.direction must be asc or desc"}), 400
            query_sql += f" ORDER BY {order_col} {direction.upper()}"

        query_sql += " LIMIT %s OFFSET %s"
        params.extend([limit, offset])

        with get_conn() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query_sql, params)
                rows = cur.fetchall()

        return jsonify({"data": rows, "count": len(rows)}), 200

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({"error": "Database error", "details": str(e)}), 500
    except Exception as e:
        return jsonify({"error": "Internal server error", "details": str(e)}), 500


@app.route("/health", methods=["GET"])
def health():
    try:
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT 1")
                cur.fetchone()
        return jsonify({"status": "ok"}), 200
    except Exception:
        return jsonify({"status": "unhealthy"}), 500


